section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/go-concurrency",
  "type": "object",
  "required": ["package", "ciCommand", "goleakTestMain"],
  "properties": {
    "package": {"type": "string"},
    "ciCommand": {"type": "string", "pattern": "go\\s+test.*-race.*-count=([1-9][0-9]+|[1-9])"},
    "goleakTestMain": {"type": "boolean", "const": true},
    "semaphoreSize": {
      "type": "object",
      "properties": {
        "value": {"type": "integer", "minimum": 1},
        "derivedFrom": {"enum": ["db_pool_size", "rate_limit", "downstream_capacity"]}
      },
      "required": ["value", "derivedFrom"]
    },
    "forbiddenPatterns": {
      "type": "array",
      "items": {"enum": [
        "go func() {",
        "wg.Add(1) inside goroutine body",
        "close(ch) outside writer",
        "select {} without ctx.Done"
      ]}
    }
  }
}

example.code:
// internal/concurrency/pool.go
type Pool struct {
    jobs chan Job
    wg   sync.WaitGroup
}

func New(ctx context.Context, workers int) *Pool {
    p := &Pool{jobs: make(chan Job, workers*2)}
    for i := 0; i < workers; i++ {
        p.wg.Add(1)                          // r6: Add before launch
        go p.run(ctx)                         // r2: explicit exit via close + ctx
    }
    return p
}

func (p *Pool) run(ctx context.Context) {
    defer p.wg.Done()
    for {
        select {
        case <-ctx.Done():                    // r7: ctx.Done branch
            return
        case job, ok := <-p.jobs:
            if !ok { return }
            job.Run(ctx)
        }
    }
}

func (p *Pool) Submit(ctx context.Context, job Job) error {
    select {
    case p.jobs <- job:
        return nil
    case <-ctx.Done():
        return ctx.Err()
    }
}

func (p *Pool) Close() {
    close(p.jobs)                              // r1: writer closes
    p.wg.Wait()
}

// REJECTED
func leakyGen(ch chan int) {
    go func() {                               // r2: no explicit exit
        for i := 0; ; i++ {
            ch <- i
        }
    }()
}

func badWg(items []int) {
    var wg sync.WaitGroup
    for _, x := range items {
        go func(v int) {
            wg.Add(1)                         // r6: Add inside body
            defer wg.Done()
            process(v)
        }(x)
    }
    wg.Wait()
}
